changeSet.sql:
DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM information_schema.columns
        WHERE table_name = 'user_profile' AND column_name = 'avatar_attachment_id'
    ) THEN
        ALTER TABLE user_profile
            ADD COLUMN avatar_attachment_id BIGINT;

        COMMENT ON COLUMN user_profile.avatar_attachment_id
            IS 'FK-less reference to attachment.id for the current profile photo. '
               'Nullable; no FK constraint so soft-deleted attachments do not violate integrity.';
    END IF;
END $$;
